// ─── TRANSACTION ID GENERATOR ─────────────────────────────────────────────────
const genTxId = () => {
  const yr = new Date().getFullYear().toString().slice(-2);
  const rand = Math.random().toString(36).slice(2,6).toUpperCase();
  return `CC${yr}-${rand}`;
};

