                  <div style={{fontFamily:G.font,fontSize:12,fontWeight:600,color:G.navy,lineHeight:1.3}}>{ql.label}{ql.external&&<span style={{fontSize:10,marginLeft:4,color:G.muted}}>↗</span>}</div>
                  {ql.sub&&<div style={{fontFamily:G.font,fontSize:10,color:G.muted,marginTop:2}}>{ql.sub}</div>}
